import java.util.*;
class Main 
{
    public static int solve (int r, int unit, int arr[], int n) 
    {
        if (arr == null)
            return -1;
        int res = r * unit;
        int sum = 0;
        int count = 0;
        for (int i = 0; i < n; i++)
        {
            sum = sum + arr[i];
            count++;
            if (sum >= res)
                break;
        }
        if(sum<res)
            return 0;
        return count;
    }

    public static void main (String[]args) 
    {
        Scanner sc = new Scanner (System.in);
        int r = sc.nextInt ();
        int unit = sc.nextInt ();
        int n = sc.nextInt ();
        int arr[] = new int[n];

        for (int i = 0; i < n; i++)
            arr[i] = sc.nextInt ();
        System.out.println (solve (r, unit, arr, n));
    } 
}

import java.util.*;
class Main 
{
    public static int numberOfCarries (int num1, int num2) 
    {
        int count = 0;
        int temp1 = num1, temp2 = num2;
        int rem = 0;
        while (temp1 != 0 && temp2 != 0)
        {
            int d1 = temp1 % 10, d2 = temp2 % 10;
            if ((d1 + d2 + rem) > 9)
    	    {
                count++;
                int sum = d1 + d2 + rem;
                sum = sum / 10;
                rem = sum;
            }
            temp1 = temp1 / 10;
            temp2 = temp2 / 10;
        } 
        while(temp1!=0)
        {
            int d1=temp1%10;
            if((d1+rem)>9)
            {
                count++;
                int sum=d1+rem;
                sum=sum/10;
                rem=sum;
            }
            temp1=temp1/10;
        }
        while(temp2!=0)
        {
            int d2=temp2%10;
            if((d2+rem)>9)
            {
                count++;
                int sum=d2+rem;
                sum=sum/10;
                rem=sum;
            }
            temp2=temp2/10;
        }
        return count;
    }
    public static void main (String[]args) 
    {
        Scanner sc = new Scanner (System.in);
        int num1 = sc.nextInt ();
        int num2 = sc.nextInt ();

        System.out.println (numberOfCarries (num1, num2));
    } 
}

import java.util.*;
class Solution 
{
    public static void replaceChar (String str, char ch1, char ch2) 
    {
        String res = "";

        for (int i = 0; i < str.length (); i++)
        {
            if (str.charAt (i) == ch1)
                res = res + ch2;
            else if (str.charAt (i) == ch2)
                res = res + ch1;
    	    else
                res = res + str.charAt (i);
        }
        System.out.println (res);
    }

    public static void main (String[]args) 
    {
        Scanner sc = new Scanner (System.in);
        String str = sc.next ();
        char ch1 = sc.next ().charAt (0);
        char ch2 = sc.next ().charAt (0);

        replaceChar (str, ch1, ch2);
    } 
}

import java.util.*;
