import java.util.*;
class Main 
{
    public static int operationsBinaryString (String str) 
    {
        if(str==null)
            return -1;
        int res = str.charAt (0) - '0';
        for (int i = 1; i < str.length ();)
        {
            char prev = str.charAt (i);
            i++;
            if (prev == 'A')
                res = res & (str.charAt (i) - '0');
            else if (prev == 'B')
                res = res | (str.charAt (i) - '0');
            else
                res = res ^ (str.charAt (i) - '0');
            i++;
        }       
        return res;
    }

    public static void main (String[]args) 
    {
        Scanner sc = new Scanner (System.in);
        String str =sc.next();
        System.out.println (operationsBinaryString (str));
    } 
}

import java.util.*;
class Solution 
{

    public static int findAutoCount (String n) 
    {
        int sum = 0;

        for (int i = 0; i < n.length (); i++)
            sum = sum + Integer.parseInt (n.charAt (i) + "");

        if (sum == n.length ())
        {
            int count = 0;
            int arr[] = new int[10];
            for (int i = 0; i < n.length (); i++)
                arr[Integer.parseInt (n.charAt (i) + "")]++;

            for (int i = 0; i < arr.length; i++)
                if (arr[i] != 0)
                    count++;
            return count;
        }
        else
            return 0;
    }

    public static void main (String[]args) 
    {
        Scanner sc = new Scanner (System.in);
        String str = sc.next ();

        System.out.println (findAutoCount (str));
    } 
}

import java.util.*;
class Solution 
{

    public static int checkPassword (String str, int n) 
    {
        if (n < 4)
            return 0;
        if (str.charAt (0) >= '0' && str.charAt (0) <= '9')
            return 0;

        int num = 0, cap = 0;
        for (int i = 0; i < n; i++)
        {
            if (str.charAt (i) == ' ' || str.charAt (i) == '/')
                return 0;
            if (str.charAt (i) >= 'A' && str.charAt (i) <= 'Z')
                cap++;
            if (str.charAt (i) >= '0' && str.charAt (i) <= '9')
                num++;
        }
        if (cap > 0 && num > 0)
            return 1;
        else
            return 0;
    }

    public static void main (String[]args) 
    {
        Scanner sc = new Scanner (System.in);
        String str = sc.next ();
        System.out.println (checkPassword (str, str.length ()));
    } 
}

import java.util.*;
class Solution 
{
    public static int differenceOfSum (int m, int n) 
    {
        int sum1 = 0, sum2 = 0;
        for (int i = 1; i <= m; i++)
        {
            if (i % n == 0)
                sum1 = sum1 + i;
    	    else    
                sum2 = sum2 + i;
        }
        return Math.abs (sum1 - sum2);
    }

    public static void main (String[]args) 
    {
        Scanner sc = new Scanner (System.in);
        int n = sc.nextInt ();
        int m = sc.nextInt ();
        System.out.println (differenceOfSum (m, n));
    } 
}

import java.util.*;
class Main 
{
    public static int largeSmallSum (int[]arr,int n) 
    {
        if(n<=3)
            return 0;
        ArrayList < Integer > even = new ArrayList < Integer > ();
        ArrayList < Integer > odd = new ArrayList < Integer > ();
        even.add (arr[0]);

        for (int i = 1; i < arr.length; i++)
        {
            if (i % 2 == 0)
                even.add (arr[i]);
            else
                odd.add (arr[i]);
        }
        Collections.sort (even);
        Collections.sort (odd);

        return even.get (even.size () - 2) + odd.get (1);
    }

    public static void main (String[]args) 
    {
        Scanner sc = new Scanner (System.in);
        int n = sc.nextInt ();
        int arr[] = new int[n]; 
        for (int i = 0; i < n; i++)
            arr[i] = sc.nextInt ();

        System.out.println (largeSmallSum (arr,n));
    } 
}

import java.util.*;
class Main 
{
    public static int productSmallestPair (int arr[], int n, int sum) 
    {
        if (n <2)
            return -1;
        int ans, temp, check;
        for (int i = 0; i < n; i++)
        {
            for (int j = i + 1; j < n; j++)
    	    {
                if (arr[i] > arr[j])
    	        {
                    temp = arr[i];
                    arr[i] = arr[j];
                    arr[j] = temp;
                }
            }
        }
        check = arr[0] + arr[1];

        if (check <= sum)
            return arr[0] * arr[1];
        else
            return 0;
    }

    public static void main (String[]args) 
    {
        Scanner sc = new Scanner (System.in);
        int sum = sc.nextInt ();
        int n = sc.nextInt ();
        int arr[] = new int[n];

        for (int i = 0; i < n; i++)
            arr[i] = sc.nextInt ();
        System.out.println (productSmallestPair (arr, n, sum));
    } 
}

import java.util.*;
class Main 
{
    public static String dectoNBase (int n, int num) 
    {
        String res = "";
        int quotient = num / n;
        ArrayList < Integer > rem = new ArrayList < Integer > ();
        rem.add (num % n);

        while(quotient != 0)
        {
            rem.add (quotient % n);
            quotient = quotient / n;
        }

        for (int i = 0; i < rem.size (); i++)
        {
            if (rem.get (i) > 9)
    	    {
                res = (char) (rem.get (i) - 9 + 64) + res;
            }
    	    else
                res = rem.get (i) + res;
        }
        return res;
    }

    public static void main (String[]args) 
    {
        Scanner sc = new Scanner (System.in);
        int n = sc.nextInt ();
        int num = sc.nextInt ();
        System.out.println (dectoNBase (n, num));
    } 
}

