// This function is identifying the number is prime or not 
bool isPrime(int n){
               bool flag = false;
               for(int i=2; i<=n/2; i++){
                              if(n%i == 0){
                                             flag = true;
                                             break;
                              }
               }
               if(flag == false && n > 1){
                              // Number is prime
                              return true;
               }
// Number is not a prime
               return false;
}

