import java.util.*;
class Solution 
{
    static int n, w;
    static int a[];
    static int b[];
    static int c[];

    public static int func (int i, int cb, int t, int ww) 
    {
        if (i == n)
        {
            if ((cb & 1) != 0)
                return 0;
        	else
                return t;
        }
        if (ww + b[i] <= w)
            return Math.max (func (i + 1, cb + c[i], t + a[i], ww + b[i]),func (i + 1, cb, t, ww));
        return func (i + 1, cb, t, ww);
    }

